contracts/BlockLabelToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title BlockLabelToken (BDL) - BEP-20 Utility Token
 * @notice Official utility token for the Block Label Web3 / DePIN ecosystem,
 *         linked to the WebKey ecosystem via the Link2E mechanism. Tokens are
 *         distributed to qualifying wallets via airdrop — no token sale.
 * @dev Built on OpenZeppelin v5. The token itself is a standard burnable /
 *      pausable ERC20. Tokenomics (team lockup, proportional burn, bonus pool)
 *      live in the separate {TeamLockup} contract so this token stays minimal
 *      and audit-friendly. Name, symbol and supply are constructor parameters.
 *
 *      Reference tokenomics (wired at deploy time):
 *        - Total supply:        10,000,000,000 BDL
 *        - Team allocation:      1,000,000,000 BDL (10%) -> held by TeamLockup
 *        - Non-team ecosystem:   9,000,000,000 BDL (90%) -> distribution/treasury
 */
contract BlockLabelToken is ERC20, ERC20Burnable, ERC20Pausable, Ownable, AccessControl {
    /// @notice Role identifier for addresses allowed to mint new tokens.
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    /// @notice Role identifier for addresses allowed to pause/unpause transfers.
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    /**
     * @param name_         Token name (e.g. "Block Label").
     * @param symbol_       Token symbol (e.g. "BDL").
     * @param initialSupply Initial supply in WHOLE tokens (e.g. 10000000000);
     *                      decimals are applied internally.
     */
    constructor(
        string memory name_,
        string memory symbol_,
        uint256 initialSupply
    ) ERC20(name_, symbol_) Ownable(msg.sender) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
        _mint(msg.sender, initialSupply * 10 ** decimals());
    }

    /**
     * @notice Mints new tokens to a specified address.
     * @dev Only callable by addresses with MINTER_ROLE. `amount` is in wei units.
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        _mint(to, amount);
    }

    /// @notice Pauses all token transfers (emergency use). Requires PAUSER_ROLE.
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /// @notice Resumes token transfers after a pause. Requires PAUSER_ROLE.
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /// @dev Required override: ERC20 + ERC20Pausable both implement _update.
    function _update(address from, address to, uint256 value)
        internal
        override(ERC20, ERC20Pausable)
    {
        super._update(from, to, value);
    }

    /// @dev Required override: ERC20 + AccessControl both implement supportsInterface.
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(AccessControl)
        returns (bool)
    {
        return
            interfaceId == type(IERC20).interfaceId ||
            super.supportsInterface(interfaceId);
    }
}

contracts/TeamLockup.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IERC20Burnable is IERC20 {
    function burn(uint256 amount) external;
}

/**
 * @title TeamLockup — Block Label (BDL) team allocation lock with proportional burn
 *
 * @notice Holds 100% of the team allocation locked at launch and burns it
 *         proportionally as the non-team ecosystem supply is burned, so the team
 *         can never dump on the market ahead of the ecosystem. Once the burn
 *         milestone is reached, the remaining team allocation unlocks as a Team
 *         Bonus Pool that funds monthly USDT bonuses with a full on-chain record.
 *
 * @dev Mechanics (per project spec):
 *
 *   Total supply        : 10,000,000,000 BDL
 *   Team allocation      :  1,000,000,000 BDL  (held by this contract, locked)
 *   Non-team burn base   :  9,000,000,000 BDL  (the denominator for progress)
 *
 *   Burn progress is measured against the NON-TEAM base (not total supply) to
 *   avoid double-counting team burns. As non-team tokens are burned through the
 *   official burn address/contract, the locked team allocation is burned to keep
 *   the same proportion:
 *
 *       targetTeamBurned = teamAllocation * cumulativeVerifiedBurned / nonTeamBase
 *
 *   capped at 50% of the team allocation. When 50% of the non-team base is burned
 *   (4,500,000,000), exactly 50% of the team allocation (500,000,000) has been
 *   burned and the remaining 50% (500,000,000) becomes fully unlockable as the
 *   Team Bonus Pool.
 *
 *   Tracked values (per spec):
 *     1. total non-team burn base        -> {nonTeamBurnBase}
 *     2. cumulative verified burned       -> {cumulativeVerifiedBurned}
 *     3. total team allocation            -> {teamAllocation}
 *     4. team allocation already burned   -> {teamAllocationBurned}
 *     5. unlock condition (50% milestone) -> {burnMilestone} / {milestoneReached}
 *
 *   Verifying "cumulative verified burned amount":
 *     - Primary (trustless): the non-team official burn happens by sending tokens
 *       to {officialBurnAddress}; its balance is read on-chain. Team burns use
 *       {IERC20Burnable.burn} (supply reduction) and do NOT land on that address,
 *       so there is no double counting.
 *     - Fallback (guarded): if the official burn instead reduces totalSupply (so a
 *       balance cannot be read), a BURN_ORACLE_ROLE holder reports the cumulative
 *       verified amount. The value is monotonic — it can only ever increase.
 */
contract TeamLockup is AccessControl, ReentrancyGuard {
    using SafeERC20 for IERC20;

    /// @notice May report verified non-team burn when it cannot be read on-chain.
    bytes32 public constant BURN_ORACLE_ROLE = keccak256("BURN_ORACLE_ROLE");

    /// @notice May release the unlocked pool and settle USDT bonuses post-milestone.
    bytes32 public constant TREASURER_ROLE = keccak256("TREASURER_ROLE");

    // ─────────────────────────── Immutable config ───────────────────────────

    /// @notice The BDL token held and burned by this contract.
    IERC20Burnable public immutable token;

    /// @notice Total team allocation locked at launch (1,000,000,000 BDL in wei).
    uint256 public immutable teamAllocation;

    /// @notice Non-team ecosystem allocation used as the burn-progress denominator.
    uint256 public immutable nonTeamBurnBase;

    /// @notice Burn milestone = 50% of the non-team base; unlocks the bonus pool.
    uint256 public immutable burnMilestone;

    // ───────────────────────────── Mutable state ────────────────────────────

    /// @notice Address where non-team burns accumulate (e.g. 0x…dEaD or burn contract).
    address public officialBurnAddress;

    /// @notice Cumulative verified non-team burned (monotonic, capped at base).
    uint256 public cumulativeVerifiedBurned;

    /// @notice Team allocation already burned (capped at 50% of the allocation).
    uint256 public teamAllocationBurned;

    /// @notice True once the 50% milestone is reached and the pool is unlocked.
    bool public bonusPoolUnlocked;

    /// @notice Stablecoin used to settle team bonuses (e.g. USDT on BSC).
    IERC20 public usdt;

    // ──────────────────────────── Bonus accounting ──────────────────────────

    /// @dev On-chain audit record for each monthly USDT bonus settlement.
    struct BonusPayment {
        address recipient; // wallet that received the bonus
        uint256 usdtAmount; // USDT amount paid (token units)
        uint256 localCurrencyValue; // valuation in local currency at payment time
        string fxRateInfo; // exchange rate / market-price reference
        string period; // settlement period, e.g. "2026-06"
        string approvalRef; // internal approval record reference
        uint256 timestamp; // block timestamp of the record
    }

    BonusPayment[] public bonusPayments;

    // ───────────────────────────────── Events ───────────────────────────────

    event VerifiedBurnSynced(uint256 cumulativeVerifiedBurned, address indexed by);
    event TeamTokensBurned(uint256 amount, uint256 totalTeamBurned);
    event MilestoneReached(uint256 cumulativeVerifiedBurned);
    event BonusPoolUnlocked(uint256 remainingTeamTokens);
    event UnlockedTeamTokensReleased(address indexed to, uint256 amount);
    event OfficialBurnAddressUpdated(address indexed newAddress);
    event UsdtUpdated(address indexed usdt);
    event BonusPaid(
        uint256 indexed id,
        address indexed recipient,
        uint256 usdtAmount,
        uint256 localCurrencyValue,
        string period,
        string approvalRef
    );

    constructor(
        address token_,
        address officialBurnAddress_,
        uint256 teamAllocation_,
        uint256 nonTeamBurnBase_,
        address admin_
    ) {
        require(token_ != address(0), "token=0");
        require(admin_ != address(0), "admin=0");
        require(teamAllocation_ > 0, "teamAllocation=0");
        require(nonTeamBurnBase_ > 0, "nonTeamBurnBase=0");

        token = IERC20Burnable(token_);
        officialBurnAddress = officialBurnAddress_;
        teamAllocation = teamAllocation_;
        nonTeamBurnBase = nonTeamBurnBase_;
        burnMilestone = nonTeamBurnBase_ / 2;

        _grantRole(DEFAULT_ADMIN_ROLE, admin_);
        _grantRole(BURN_ORACLE_ROLE, admin_);
        _grantRole(TREASURER_ROLE, admin_);
    }

    // ─────────────────────────── Burn progress sync ─────────────────────────

    /**
     * @notice Non-team burned as observed on-chain from the official burn address.
     * @dev Team burns use {IERC20Burnable.burn} (supply reduction) and never land
     *      on this address, so the balance reflects non-team burns only.
     */
    function observedNonTeamBurned() public view returns (uint256) {
        if (officialBurnAddress == address(0)) return 0;
        return token.balanceOf(officialBurnAddress);
    }

    /**
     * @notice Sync burn progress from the on-chain official burn address and apply
     *         the proportional team burn. Callable by anyone (trustless, keeper-able).
     */
    function syncBurnFromAddress() external nonReentrant {
        _applyVerifiedBurn(observedNonTeamBurned());
    }

    /**
     * @notice Report cumulative verified non-team burned when it cannot be read
     *         on-chain (e.g. the official burn reduces totalSupply). Monotonic.
     * @param cumulativeAmount New cumulative figure; must be >= the current value.
     */
    function reportVerifiedBurn(uint256 cumulativeAmount)
        external
        onlyRole(BURN_ORACLE_ROLE)
        nonReentrant
    {
        require(cumulativeAmount >= cumulativeVerifiedBurned, "must not decrease");
        _applyVerifiedBurn(cumulativeAmount);
    }

    function _applyVerifiedBurn(uint256 observed) internal {
        if (observed > nonTeamBurnBase) observed = nonTeamBurnBase;
        if (observed > cumulativeVerifiedBurned) {
            cumulativeVerifiedBurned = observed;
            emit VerifiedBurnSynced(observed, msg.sender);
        }
        _syncTeamBurn();
    }

    /// @dev Burns team tokens up to the proportional target (capped at 50%) and
    ///      unlocks the bonus pool once the milestone is reached.
    function _syncTeamBurn() internal {
        uint256 maxBurn = teamAllocation / 2; // proportional burn caps at 50%
        uint256 target = (teamAllocation * cumulativeVerifiedBurned) / nonTeamBurnBase;
        if (target > maxBurn) target = maxBurn;

        if (target > teamAllocationBurned) {
            uint256 toBurn = target - teamAllocationBurned;
            uint256 bal = token.balanceOf(address(this));
            if (toBurn > bal) toBurn = bal; // never burn more than held
            if (toBurn > 0) {
                teamAllocationBurned += toBurn;
                token.burn(toBurn);
                emit TeamTokensBurned(toBurn, teamAllocationBurned);
            }
        }

        if (!bonusPoolUnlocked && cumulativeVerifiedBurned >= burnMilestone) {
            bonusPoolUnlocked = true;
            emit MilestoneReached(cumulativeVerifiedBurned);
            emit BonusPoolUnlocked(token.balanceOf(address(this)));
        }
    }

    // ──────────────────────────────── Views ─────────────────────────────────

    /// @notice Remaining locked team tokens currently held (the future bonus pool).
    function remainingLockedTeam() external view returns (uint256) {
        return token.balanceOf(address(this));
    }

    /// @notice True once 50% of the non-team base has been burned.
    function milestoneReached() public view returns (bool) {
        return cumulativeVerifiedBurned >= burnMilestone;
    }

    /// @notice Burn progress against the non-team base, in basis points (0–10000).
    function burnProgressBps() external view returns (uint256) {
        return (cumulativeVerifiedBurned * 10_000) / nonTeamBurnBase;
    }

    /// @notice Number of recorded USDT bonus settlements.
    function bonusPaymentsCount() external view returns (uint256) {
        return bonusPayments.length;
    }

    // ──────────────────────── Admin / pool management ───────────────────────

    function setOfficialBurnAddress(address a) external onlyRole(DEFAULT_ADMIN_ROLE) {
        officialBurnAddress = a;
        emit OfficialBurnAddressUpdated(a);
    }

    function setUsdt(address usdt_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        usdt = IERC20(usdt_);
        emit UsdtUpdated(usdt_);
    }

    /**
     * @notice Release unlocked team BDL to a treasury/bonus wallet. Only allowed
     *         after the milestone unlocks the pool, so tokens cannot reach the
     *         market early.
     */
    function releaseUnlockedTeamTokens(address to, uint256 amount)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
        nonReentrant
    {
        require(bonusPoolUnlocked, "locked: milestone not reached");
        require(to != address(0), "to=0");
        IERC20(address(token)).safeTransfer(to, amount);
        emit UnlockedTeamTokensReleased(to, amount);
    }

    // ─────────────────────────── USDT team bonuses ──────────────────────────

    /**
     * @notice Settle a monthly USDT bonus from this contract's USDT balance and
     *         record full audit data on-chain (the tx hash is the payment record).
     * @dev Requires the bonus pool to be unlocked (milestone reached) and USDT set.
     */
    function payBonusUSDT(
        address recipient,
        uint256 usdtAmount,
        uint256 localCurrencyValue,
        string calldata fxRateInfo,
        string calldata period,
        string calldata approvalRef
    ) external onlyRole(TREASURER_ROLE) nonReentrant returns (uint256 id) {
        require(bonusPoolUnlocked, "locked: milestone not reached");
        require(recipient != address(0), "recipient=0");
        require(address(usdt) != address(0), "usdt unset");

        usdt.safeTransfer(recipient, usdtAmount);
        id = _recordBonus(
            recipient,
            usdtAmount,
            localCurrencyValue,
            fxRateInfo,
            period,
            approvalRef
        );
    }

    /**
     * @notice Record a USDT bonus that was paid from an external wallet (audit
     *         only, no transfer) — keeps all settlements in one verifiable ledger.
     */
    function recordExternalBonus(
        address recipient,
        uint256 usdtAmount,
        uint256 localCurrencyValue,
        string calldata fxRateInfo,
        string calldata period,
        string calldata approvalRef
    ) external onlyRole(TREASURER_ROLE) returns (uint256 id) {
        id = _recordBonus(
            recipient,
            usdtAmount,
            localCurrencyValue,
            fxRateInfo,
            period,
            approvalRef
        );
    }

    function _recordBonus(
        address recipient,
        uint256 usdtAmount,
        uint256 localCurrencyValue,
        string calldata fxRateInfo,
        string calldata period,
        string calldata approvalRef
    ) internal returns (uint256 id) {
        bonusPayments.push(
            BonusPayment({
                recipient: recipient,
                usdtAmount: usdtAmount,
                localCurrencyValue: localCurrencyValue,
                fxRateInfo: fxRateInfo,
                period: period,
                approvalRef: approvalRef,
                timestamp: block.timestamp
            })
        );
        id = bonusPayments.length - 1;
        emit BonusPaid(id, recipient, usdtAmount, localCurrencyValue, period, approvalRef);
    }
}

